//! rf_beacon — protocol69 FOIL-over-RF discovery beacon for the resilient R1 mesh
//! (docs/R1_MESH_PROTOCOL69.md section 1).
//!
//! A `Protocol69RfBeacon` is the over-the-air liveness signal an SDR-equipped node
//! broadcasts. The RF-gossip bridge (`bin/rf-gossip-bridge`) decodes it, validates the
//! projection envelope FAIL-CLOSED (a node that cannot produce `66 XOR 7 = 69` is
//! treated as absent), and injects it into stream-2010 gossip as a direct heartbeat —
//! giving the mesh an out-of-band membership channel that survives WiFi partition.
//!
//! The SDR transport itself is hardware-gated (R1_MESH_PROTOCOL69.md step 5: the NESDR
//! USB-OTG path on the R1 is untested). This module is the transport-agnostic frame plus
//! the bridge-into-gossip mapping, both fully unit-testable without a radio.
use crate::mesh_gossip::{peer_heartbeat_frame, PeerInfo};
use crate::protocol69::{
    build_protocol69_projection_envelope, validate_protocol69_projection_envelope,
    Protocol69ProjectionEnvelope,
};
use serde::{Deserialize, Serialize};

/// The RF beacon payload. Mirrors the gossip `PeerInfo` plus the self-authenticating
/// protocol69 projection envelope. Carried as JSON over the SDR (or the file/loopback
/// sources used for testing).
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69RfBeacon {
    /// The self-authenticating gate (`66 XOR 7 = 69`). Validated fail-closed on receipt.
    pub envelope: Protocol69ProjectionEnvelope,
    pub node_id: String,
    pub model_id: String,
    pub stage_lo: usize,
    pub stage_hi: usize,
    pub role: String,
    /// Data-plane host (fat-station HTTP / `/chain`) and ports, mirroring `PeerInfo`.
    pub host: String,
    pub data_port: u16,
    pub gossip_port: u16,
    pub epoch: u64,
    pub beacon_seq: u64,
}

impl Protocol69RfBeacon {
    /// Build a beacon carrying the canonical (valid) projection envelope.
    #[allow(clippy::too_many_arguments)]
    pub fn canonical(
        node_id: impl Into<String>,
        model_id: impl Into<String>,
        stage_lo: usize,
        stage_hi: usize,
        role: impl Into<String>,
        host: impl Into<String>,
        data_port: u16,
        gossip_port: u16,
        epoch: u64,
        beacon_seq: u64,
    ) -> Self {
        Self {
            envelope: build_protocol69_projection_envelope(),
            node_id: node_id.into(),
            model_id: model_id.into(),
            stage_lo,
            stage_hi,
            role: role.into(),
            host: host.into(),
            data_port,
            gossip_port,
            epoch,
            beacon_seq,
        }
    }

    /// Serialize for the RF payload (JSON; the SDR carries these bytes). Symmetric with
    /// `decode`.
    pub fn encode(&self) -> Vec<u8> {
        serde_json::to_vec(self).unwrap_or_default()
    }

    /// Parse a beacon from received bytes; `None` if malformed.
    pub fn decode(buf: &[u8]) -> Option<Self> {
        serde_json::from_slice(buf).ok()
    }

    /// Map an RF beacon to a gossip `PeerInfo`, FAIL-CLOSED: the projection envelope must
    /// validate (`66 XOR 7 = 69`) or the node is treated as absent (`Err`). A drifted or
    /// forged envelope never enters the registry.
    pub fn to_peer_info(&self) -> Result<PeerInfo, String> {
        validate_protocol69_projection_envelope(&self.envelope)?;
        Ok(PeerInfo {
            node_id: self.node_id.clone(),
            model_id: self.model_id.clone(),
            layer_start: self.stage_lo,
            layer_end: self.stage_hi,
            role: self.role.clone(),
            host: self.host.clone(),
            data_port: self.data_port,
            gossip_port: self.gossip_port,
            epoch: self.epoch,
            // RF beacons carry identity/topology only; health rides the UDP heartbeat.
            status: crate::mesh_gossip::NodeStatus::default(),
        })
    }

    /// Build the stream-2010 direct-heartbeat FlowFrame that injects this RF-discovered
    /// node into a fat-station's gossip registry. Fail-closed via `to_peer_info`.
    pub fn to_gossip_frame(&self, sequence: u32) -> Result<Vec<u8>, String> {
        let peer = self.to_peer_info()?;
        Ok(peer_heartbeat_frame(&peer, sequence))
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::mesh_gossip::decode_heartbeat_frame;

    fn sample() -> Protocol69RfBeacon {
        Protocol69RfBeacon::canonical(
            "r1-rf",
            "qwen2",
            12,
            24,
            "exit",
            "10.0.0.240",
            8090,
            9090,
            42,
            1,
        )
    }

    #[test]
    fn beacon_round_trips() {
        let b = sample();
        let back = Protocol69RfBeacon::decode(&b.encode()).expect("decode");
        assert_eq!(back.node_id, "r1-rf");
        assert_eq!((back.stage_lo, back.stage_hi), (12, 24));
        assert_eq!(back.gossip_port, 9090);
    }

    #[test]
    fn canonical_beacon_maps_to_peer_and_frame() {
        let b = sample();
        let peer = b.to_peer_info().expect("valid envelope -> peer");
        assert_eq!(peer.node_id, "r1-rf");
        assert_eq!(peer.layer_start, 12);
        assert_eq!(peer.layer_end, 24);
        assert_eq!(peer.data_port, 8090);
        // The injected gossip frame must decode back to the same advertised peer, i.e.
        // a real fat-station recv loop would note_direct exactly this node.
        let frame = b.to_gossip_frame(7).expect("frame");
        let decoded = decode_heartbeat_frame(&frame).expect("decode heartbeat");
        assert_eq!(decoded.node_id, "r1-rf");
        assert_eq!(decoded.layer_start, 12);
        assert_eq!(decoded.gossip_port, 9090);
    }

    #[test]
    fn drifted_envelope_is_fail_closed() {
        let mut b = sample();
        b.envelope.expected_projection = 68; // 66 ^ 7 = 69, not 68
        assert!(
            b.to_peer_info().is_err(),
            "drifted projection must be rejected"
        );
        assert!(
            b.to_gossip_frame(0).is_err(),
            "no frame for an invalid beacon"
        );
    }

    #[test]
    fn forged_operands_are_fail_closed() {
        let mut b = sample();
        // A forged beacon with internally-consistent but non-canonical operands.
        b.envelope.broadcast_symbol = 99;
        b.envelope.expected_projection = 99 ^ 7;
        assert!(
            b.to_peer_info().is_err(),
            "non-canonical operands must be rejected"
        );
    }
}
